return (
  <div className="grid flex-1 gap-12 lg:gap-24">
    <h2 className="sr-only">
      {type.charAt(0).toUpperCase() + type.slice(1)} Charts
    </h2>
    <div className="grid flex-1 scroll-mt-20 items-stretch gap-10 md:grid-cols-2 md:gap-6 lg:grid-cols-3 xl:gap-10">
      {Array.from({ length: 12 }).map((_, index) => {
        const chart = prefetchedCharts[index]
        return chart ? (
          <ChartDisplay
            key={chart.name}
            chart={chart}
            style={activeStyle.name}
            className={cn(chart.fullWidth && "md:col-span-2 lg:col-span-3")}
          />
        ) : (
          <div
            key={`empty-${index}`}
            className="hidden aspect-square w-full rounded-lg border border-dashed xl:block"
          />
        )
      })}
    </div>
  </div>
)

return (
  <Card className={cn("gap-0", className)}>
    <CardContent className="flex flex-col gap-2">
      <CardDescription className="text-xs uppercase">
        {metric.label}
      </CardDescription>
      <CardTitle className="text-5xl tracking-tight lowercase">
        {metric.value}
      </CardTitle>
      <CardDescription>
        {metric.trend === "up" ? (
          <TrendingUpIcon className="inline-block size-2.5 text-muted-foreground" />
        ) : (
          <TrendingDownIcon className="inline-block size-2.5 text-muted-foreground" />
        )}{" "}
        <span className="text-foreground">{metric.comparison}</span>{" "}
        <span>{metric.change}</span>
      </CardDescription>
    </CardContent>
  </Card>
)

return (
  <div className="border-t border-border bg-muted/10">
    <div className="px-4 py-2 flex items-center gap-2">
      <div className="h-px flex-1 bg-border" />
      <span className="text-[10px] font-medium uppercase tracking-wider text-muted-foreground shrink-0">
        Sub-agent {childRuns.length === 1 ? 'call' : 'calls'} (
        {childRuns.length})
      </span>
      <div className="h-px flex-1 bg-border" />
    </div>
    <div className="px-4 pb-3 flex flex-col gap-2">
      {childRuns.map(childRun => (
        <NestedRunCard
          key={childRun.run.id}
          childRun={childRun}
          expandedSteps={expandedSteps}
          toggleStep={toggleStep}
          parseJson={parseJson}
          formatDuration={formatDuration}
          depth={depth + 1}
        />
      ))}
    </div>
  </div>
);

return (
  <PageMetadata
    title={title}
    description={description}
    keywords={keywords}
    image={image}
  >
    <meta property="og:type" content="article" />
    <meta property="article:published_time" content={date} />
    {/* TODO double check those article meta array syntaxes, see https://ogp.me/#array */}
    {authors.some((author) => author.url) && (
      <meta
        property="article:author"
        content={authors
          .map((author) => author.url)
          .filter(Boolean)
          .join(',')}
      />
    )}
    {tags.length > 0 && (
      <meta
        property="article:tag"
        content={tags.map((tag) => tag.label).join(',')}
      />
    )}
  </PageMetadata>
);

export const createErrorResponse = (
  errorType: ErrorType | ILobeAgentRuntimeErrorType,
  body?: any,
) => {
  const statusCode = getStatus(errorType);

  const data: ErrorResponse = { body, errorType };

  if (typeof statusCode !== 'number' || statusCode < 200 || statusCode > 599) {
    console.error(
      `current StatusCode: \`${statusCode}\` .`,
      'Please go to `./src/app/api/errorResponse.ts` to defined the statusCode.',
    );
  }

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };

  // Add X-Auth-Required header for real authentication failures
  // This allows the client to distinguish between auth failures and other 401 errors (e.g., invalid API keys)
  if (AUTH_REQUIRED_ERROR_TYPES.has(errorType as ErrorType)) {
    headers[AUTH_REQUIRED_HEADER] = 'true';
  }

  return new Response(JSON.stringify(data), { headers, status: statusCode });
};

config.providers = config.providers.map((provider) => {
  const { id } = typeof provider === "function" ? provider({}) : provider
  const ID = id.toUpperCase().replace(/-/g, "_")
  const clientId = envObject[`AUTH_${ID}_ID`]
  const clientSecret = envObject[`AUTH_${ID}_SECRET`]
  const issuer = envObject[`AUTH_${ID}_ISSUER`]
  const apiKey = envObject[`AUTH_${ID}_KEY`]
  const finalProvider =
    typeof provider === "function"
      ? provider({ clientId, clientSecret, issuer, apiKey })
      : provider
  if (finalProvider.type === "oauth" || finalProvider.type === "oidc") {
    finalProvider.clientId ??= clientId
    finalProvider.clientSecret ??= clientSecret
    finalProvider.issuer ??= issuer
  } else if (finalProvider.type === "email") {
    finalProvider.apiKey ??= apiKey
  }
  return finalProvider
})
